        // track down why turns never reach the browser.
        console.log(`[sidecar][event] session=${sessionId} type=${event.type}`);
        switch (event.type) {
          case "message_update": {
            const assistantEvent = event.assistantMessageEvent;
            if (assistantEvent.type === "text_delta") {
