              sessionId,
              "compacting",
              "Compacting context...",
              "info",
              { reason: event.reason },
            );
            break;
          case "compaction_end":
            compactionActive = false;
            if (event.willRetry) {
              pendingResult = null;
            }
            sendStatusToSocket(
              socket,
              sessionId,
              event.errorMessage ? "compaction_failed" : "compacted",
              event.errorMessage || "Context compacted.",
              event.errorMessage ? "warning" : "info",
              {
                reason: event.reason,
                willRetry: event.willRetry === true,
                aborted: event.aborted === true,
              },
            );
