export function parseStoredTurnBlocks(
  fullMessage: string | null | undefined,
  createBlockId: () => string,
): TurnBlock[] {
  if (!fullMessage) {
    return [];
  }

  let events: SSEEvent[];
  try {
    events = extractStoredEvents(fullMessage);
  } catch {
    return [];
  }

  const blocks: TurnBlock[] = [];
  for (const event of events) {
    applyTurnEventToBlocks(blocks, event, createBlockId);
  }
  return blocks;
}

import { useCallback, useRef, useState } from "react";
import { cancelSession, streamPrompt, type ThinkingLevel } from "../api/client";
import {
  applyTurnEventToBlocks,
  blocksToContent,
  type TurnBlock,
  type TurnStatus,
} from "../utils/turnEvents";

export type { TurnBlock } from "../utils/turnEvents";

export interface ChatMessage {
  id: string;
  role: "user" | "assistant" | "error";
  content: string;
  blocks: TurnBlock[];
  streaming?: boolean;
  turnStatus?: TurnStatus;
  timestamp: number;
}

let messageIdCounter = 0;
function nextId(): string {
  return `msg-${Date.now()}-${++messageIdCounter}`;
}

export type RunState = "idle" | "running" | "stopping";

export function useAgentStream(sessionId: string | undefined) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [runState, setRunState] = useState<RunState>("idle");
  const abortRef = useRef<AbortController | null>(null);
  const queuedPromptRef = useRef<{
    prompt: string;
    model?: string;
    thinking?: ThinkingLevel;
  } | null>(null);

  const startPrompt = useCallback(
    async (prompt: string, model?: string, thinking?: ThinkingLevel) => {
      if (!sessionId) return;
      const normalizedPrompt = prompt.trim();
      if (!normalizedPrompt) return;

      setMessages((prev) => [
        ...prev,
        {
          id: nextId(),
          role: "user",
          content: normalizedPrompt,
          blocks: [],
          timestamp: Date.now(),
        },
      ]);

      setRunState("running");
      const controller = new AbortController();
      abortRef.current = controller;

      const turnId = nextId();
      const blocks: TurnBlock[] = [];
      let rafId: number | null = null;
      let turnStatus: TurnStatus = "completed";

      function upsertTurn(done = false) {
        const allText = blocksToContent(blocks);
        const snapshot = blocks.map((b) => ({ ...b }));

        setMessages((prev) => {
          const msg: ChatMessage = {
            id: turnId,
            role: "assistant",
            content: allText,
            blocks: snapshot,
            streaming: !done,
            turnStatus: done ? turnStatus : undefined,
            timestamp: Date.now(),
          };
          const idx = prev.findIndex((m) => m.id === turnId);
          if (idx >= 0) {
            const next = [...prev];
            next[idx] = msg;
            return next;
          }
          return [...prev, msg];
        });
      }

      function scheduleUpsert(done = false) {
        if (done) {
          if (rafId) cancelAnimationFrame(rafId);
          rafId = null;
          upsertTurn(true);
          return;
        }
        if (rafId) return;
        rafId = requestAnimationFrame(() => {
          rafId = null;
          upsertTurn(false);
        });
      }

      try {
        for await (const event of streamPrompt(
          sessionId,
          normalizedPrompt,
          model,
          thinking,
          controller.signal,
        )) {
          const applyResult = applyTurnEventToBlocks(blocks, event, nextId);
          if (applyResult.status) {
            turnStatus = applyResult.status;
            scheduleUpsert(true);
            if (applyResult.status !== "completed" || event.type === "result") {
              break;
            }
            continue;
          }
          if (applyResult.changed) {
            scheduleUpsert();
          }
        }
      } catch (e) {
        if (!(e instanceof DOMException && e.name === "AbortError")) {
          blocks.push({
            id: nextId(),
            type: "error",
            text: e instanceof Error ? e.message : "Stream failed",
          });
          turnStatus = "failed";
          scheduleUpsert(true);
        }
      } finally {
        if (rafId) cancelAnimationFrame(rafId);
        abortRef.current = null;

        const queuedPrompt = queuedPromptRef.current;
        queuedPromptRef.current = null;
        setRunState("idle");

        // Always replay a queued steering prompt once the active run finishes.
        if (queuedPrompt) {
          void startPrompt(
            queuedPrompt.prompt,
            queuedPrompt.model,
            queuedPrompt.thinking,
          );
        }
      }
    },
    [sessionId],
  );

  const cancel = useCallback(async () => {
    if (runState !== "running") return;
    setRunState("stopping");
    if (sessionId) {
      try {
        await cancelSession(sessionId);
      } catch {
        /* best-effort */
      }
    }
  }, [sessionId, runState]);

  const sendPrompt = useCallback(
    async (prompt: string, model?: string, thinking?: ThinkingLevel) => {
      if (!sessionId) return;
      const normalizedPrompt = prompt.trim();
      if (!normalizedPrompt) return;

      if (runState === "running") {
        // Queue steering prompt and request stop
        queuedPromptRef.current = { prompt: normalizedPrompt, model, thinking };
        await cancel();
        return;
      }

      if (runState === "stopping") {
        // Replace queued steering prompt
        queuedPromptRef.current = { prompt: normalizedPrompt, model, thinking };
        return;
      }

      // runState === "idle", start normally
      await startPrompt(normalizedPrompt, model, thinking);
    },
    [cancel, runState, startPrompt],
  );

  return {
    messages,
    sendPrompt,
    cancel,
    runState,
    setMessages,
    streaming: runState === "running" || runState === "stopping",
  };
}

import { describe, expect, it } from "vitest";

import {
  applyTurnEventToBlocks,
  blocksToContent,
  parseStoredTurnBlocks,
  type TurnBlock,
} from "../turnEvents";

describe("turnEvents", () => {
  it("replays stored thinking, tool use, tool output, and assistant text", () => {
    const storedTurn = JSON.stringify({
      schema: "yinshi.assistant_turn.v1",
      events: [
        {
          type: "assistant",
          message: { content: [{ type: "thinking", thinking: "Inspect files." }] },
        },
        {
          type: "tool_use",
          id: "tool-1",
          name: "read",
          input: { path: "README.md" },
        },
        {
          type: "tool_result",
          tool_use_id: "tool-1",
          content: "# Project",
        },
        {
          type: "assistant",
          message: { content: [{ type: "text", text: "Done" }] },
        },
        { type: "result", usage: {} },
      ],
    });
    let blockIndex = 0;

    const blocks = parseStoredTurnBlocks(storedTurn, () => `block-${++blockIndex}`);

    expect(blocks).toEqual([
      { id: "block-1", type: "thinking", text: "Inspect files." },
      {
        id: "tool-1",
        type: "tool_use",
        toolName: "read",
        toolInput: { path: "README.md" },
        toolId: "tool-1",
        toolOutput: "# Project",
        toolError: undefined,
      },
      { id: "block-2", type: "text", text: "Done" },
    ]);
    expect(blocksToContent(blocks)).toBe("Done");
  });

  it("keeps legacy result-only full messages as empty replay blocks", () => {
    const legacyFullMessage = JSON.stringify({
      type: "message",
      data: { type: "result", usage: {} },
    });

    const blocks = parseStoredTurnBlocks(legacyFullMessage, () => "block-1");

    expect(blocks).toEqual([]);
  });

  it("keeps status events visible without adding transcript text", () => {
    const blocks: TurnBlock[] = [];

    const result = applyTurnEventToBlocks(
      blocks,
      {
        type: "status",
        status: "compacting",
        message: "Compacting context...",
        severity: "info",
      },
      () => "block-1",
    );

    expect(result).toEqual({ changed: true });
    expect(blocks).toEqual([
      {
        id: "block-1",
        type: "status",
        text: "Compacting context...",
        severity: "info",
      },
    ]);
    expect(blocksToContent(blocks)).toBe("");
  });

  it("updates streaming tool input from content block deltas", () => {
    const blocks: TurnBlock[] = [];
    let blockIndex = 0;
    const nextBlockId = () => `block-${++blockIndex}`;

    applyTurnEventToBlocks(
      blocks,
      {
        type: "content_block_start",
        content_block: { type: "tool_use", id: "tool-2", name: "bash" },
      },
      nextBlockId,
    );
    applyTurnEventToBlocks(
      blocks,
      {
        type: "content_block_delta",
        delta: { type: "input_json_delta", partial_json: "{\"command\":" },
      },
      nextBlockId,
    );
    applyTurnEventToBlocks(
      blocks,
      {
        type: "content_block_delta",
        delta: { type: "input_json_delta", partial_json: "\"pytest\"}" },
      },
      nextBlockId,
    );
    applyTurnEventToBlocks(blocks, { type: "content_block_stop" }, nextBlockId);

    expect(blocks).toEqual([
      {
        id: "tool-2",
        type: "tool_use",
        toolName: "bash",
        toolInput: { command: "pytest" },
        toolId: "tool-2",
      },
    ]);
  });
});

